147:  * props.put(StreamsConfig.BOOTSTRAP_SERVERS_CONFIG, "localhost:9092");
148:  * props.put(StreamsConfig.DEFAULT_KEY_SERDE_CLASS_CONFIG, Serdes.String().getClass());
149:  * props.put(StreamsConfig.DEFAULT_VALUE_SERDE_CLASS_CONFIG, Serdes.String().getClass());
150:  *
151:  * StreamsBuilder builder = new StreamsBuilder();
152:  * builder.<String, String>stream("my-input-topic").mapValues(value -> String.valueOf(value.length())).to("my-output-topic");
153:  *
154:  * KafkaStreams streams = new KafkaStreams(builder.build(), props);
155:  * streams.start();
156:  * }</pre>
